var e=JSON.parse(`[{"id":"L2_1","type":"narration","speaker":null,"text":{"KOREA":"처음 만났던 순간부터 줄곧 생각해왔어.","JPN":"初めて会った瞬間からずっと思っていたわ。","ENG":"I've been thinking about it ever since we first met.","TWN":"從第一次見面起，我就一直在想。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"전대장으로 내가 선택되지 않았다면, 다 그럴만한 이유가 있을 거야.","JPN":"私が戦隊長に選ばれなかったら、それなりの理由があるはず。","ENG":"If I wasn't chosen as the next Commander, I'm sure there's a good reason.","TWN":"如果我沒有被選為戰隊長，一定是有充分理由的。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"전대장으로 그 아이가 선택되었다면, 다 그럴만한 이유가 있을 거고.","JPN":"あの子が戦隊長に選ばれたら、それなりの理由があるはずだし。","ENG":"And if she is chosen as our next Commander, I'm sure there's good reason for that too.","TWN":"如果那個孩子被選為戰隊長，也一定是有充分理由的。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"그리니까 우선 그 아이를 만나보자.","JPN":"だから、まずはあの子に会ってみよう。","ENG":"So first, let's go meet her.","TWN":"所以，我們先去見見那個孩子吧。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"결정은…… 길고양이가 새로운 집을 찾은 뒤에 해도 늦지 않으니까.","JPN":"野良猫が新しい家を探した後に決めても……遅くないから。","ENG":"It won't be too late... to decide after we bring her to her new home.","TWN":"至於決定……等流浪的小貓找到新家之後再做也不遲。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L10_1","type":"narration","speaker":null,"text":{"KOREA":"아무리 내 의지와 관계없었던 일이라고 해도.","JPN":"いくら自分の意志とは関係のないことだとしても。","ENG":"Even if this is something that is unrelated to my will.","TWN":"即使那是與我的意志無關的事情。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L11_1","type":"narration","speaker":null,"text":{"KOREA":"최선이라는 명분으로 내가 너에게 어떤 희생을 강요했다면.","JPN":"最善という名目で私があなたに何らかの犠牲を押しつけたのなら。","ENG":"And while I forced you to make sacrifices in the name of having the best outcome.","TWN":"但我還是以最好的選擇為理由，強迫你做出了犧牲。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L12_1","type":"narration","speaker":null,"text":{"KOREA":"나는 반드시 그 책임을 져야만 한다고 말이야.","JPN":"私は必ずその責任を負うべきだわ。","ENG":"I must take responsibility for all of it.","TWN":"要對此負責的人，是我。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"반송장인 주제에 잘도 깡총깡총 뛰어다니네.","JPN":"死んでいるも同然のくせに、よくピョンピョンと飛びまわっていられるわね。","ENG":"For half a corpse, you seem to jump around pretty well.","TWN":"都快死了，話還這麼多。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":null}},"sfx":"FX_CUTSCEN_SWORD_HIT"},{"id":"L18_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"빙결 능력이라는 게 원래 이 정도까지 할 수 있는 거야?","JPN":"氷結能力って、元々こんなに使えるものなの？","ENG":"I didn't know freezing abilities could be this useful.","TWN":"凍結能力真的有這麼神奇？"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"아니면 네가 환상종의 후예라서 그런 걸까?","JPN":"それとも、あなたが幻想種の末裔だからかしら。","ENG":"Or is it because you're a descendant of Bygones?","TWN":"還是因為你是夢幻品種的後裔？"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"시끄러워……!!","JPN":"うるさい……！！","ENG":"Shut up...!!","TWN":"閉嘴……！！"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L27_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"돌아올 곳이 있고, 널 기다리는 사람들이 있는데……. 네가 왜 길고양이겠어.","JPN":"帰る場所があって、あなたを待ってる人たちがいるのに……あなたが野良猫なわけないでしょ。","ENG":"You have a home, and people waiting for you to come back... You're not a stray cat.","TWN":"你有家可回，還有人在等你……你怎麼會是流浪貓呢？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"넌 결국 훌륭하게 스스로 그림자를 끊어냈잖아?","JPN":"あなたは結局、自分で見事シャドウを断ち切ったじゃない。","ENG":"Plus, you defeated your own Shadow with excellence, no?","TWN":"最後，你自己成功斬斷了暗影吧？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"그러니 이제부터 넌 야크샤의 일원이자, 우리의 가족이야.","JPN":"だから、これからあなたはヤクシャーの一員で、私たちの家族よ。","ENG":"Now, you're a member of the Yaksha Division, and also our family.","TWN":"所以從現在開始，你不僅是夜叉的一員，也是我們這個大家庭的一員了。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L30_1","type":"narration","speaker":null,"text":{"KOREA":"소중한 사람을 잃고, 텅 비어 버린 너의 마음을 채워 줄 수 있도록.","JPN":"大事な人を失って、空っぽになったあなたの心を満たしてあげるために。","ENG":"To fill your empty heart after losing someone dear to you.","TWN":"我願意成為你的朋友。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L31_1","type":"narration","speaker":null,"text":{"KOREA":"내가 너의 친구가 되어주어야만 한다고.","JPN":"私があなたの友だちになる。","ENG":"I should become your friend.","TWN":"我願意成為你的家人。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L32_1","type":"narration","speaker":null,"text":{"KOREA":"내가 너의 가족이 되어주어야만 한다고.","JPN":"私があなたの家族になるの。","ENG":"I should become your family.","TWN":"我願意去填補你那顆失去重要之人後，空虛的內心。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"쳇, 어딜 쏘는 거야? 네 상대는 카르멘이 아니라 나라고!!","JPN":"チッ、どこに撃ってるのかしら！　あなたの相手はカルメンではなくて私よ！","ENG":"Tsk, what are you even aiming at? You're fighting me, not Carmen!!","TWN":"嘖，你往哪裡瞄準呢？你的對手不是卡門，而是我！！"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"이쪽을 보라고!! 끝까지 날 무시할 셈이야!?","JPN":"こっちを見なさい！！　私のことは最後まで眼中にないの！？","ENG":"Look over here!! Are you going to ignore me until you draw your last breath?!","TWN":"看這邊！！難道你要一直無視我嗎？！"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"비켜……! 비키라고……!!","JPN":"どいて……！　どいてよ……！！","ENG":"Move...! I said, get out of my way...!!","TWN":"讓開……！叫你讓開……！"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"나한테 너 같은 건, 아무래도 좋아!!","JPN":"あなたなんて、どうでもいい！！","ENG":"I don't care for the likes of you!!","TWN":"你算什麼東西！！"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"LIONEL_YAKSHA_NPC_NULL","text":{"KOREA":"내가 너를 그곳으로부터 구해주겠다.","JPN":"私がお前をここから救ってやろう。","ENG":"I'll save you from this place.","TWN":"我會把你從這個地方救出來。"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L47_1","type":"dialog","speaker":"LIONEL_YAKSHA_NPC_NULL","text":{"KOREA":"그러니 나를 따라오지 않겠니?","JPN":"だから、私について来ないか？","ENG":"So won't you follow me?","TWN":"所以，不來跟著我嗎？"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L48_1","type":"narration","speaker":null,"text":{"KOREA":"그래. 그 사람이 나에게 해주었던 것처럼.","JPN":"そう。あの人が私にしてくれたように。","ENG":"Yeah. Just like what he did to me.","TWN":"是了。就像他為我做的那樣。"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L49_1","type":"narration","speaker":null,"text":{"KOREA":"나도 똑같이 너의 마음을 책임져야만 한다고 생각했어.","JPN":"私も、あなたの心に責任を取るべきだと思ってた。","ENG":"I thought I needed to take responsibility for your heart like he did for mine.","TWN":"我想我也需要用他對我的真心一樣對你負責。"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":" 크윽……!!","JPN":" くっ……！！","ENG":"Kgh...!!","TWN":"咳……！！"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"BASS_HARMONY_NPC_NULL","text":{"KOREA":" 우우후, 다 죽어가는 줄 알았는데, 생각보다 토끼가 제법이네~?","JPN":" ふーん、死にかけのウサギかと思ったら、結構やるじゃな～い","ENG":"Uhu huu, I thought you were dead but you're tougher than you look.","TWN":"呵呵呵，我以為快死了呢，結果這隻兔子比我想像的還堅強得多～？"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASS_HARMONY_NPC_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L10_1","type":"dialog","speaker":"BASS_HARMONY_NPC_NULL","text":{"KOREA":" 셰나, 밀리는 것 같은데 힘들면 조금 도와줄까?","JPN":" シェナ、押されてるみたいだけど、疲れたのなら少し手伝いましょうか？","ENG":"Shena, you seem to be struggling, do you want some help?","TWN":"世娜，你好像很吃力啊，需要幫忙嗎？"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASS_HARMONY_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":" 닥쳐!! 끼어들면 죽여버릴 거야!!","JPN":" うるさい！！　手を出したら殺すわよ！！","ENG":"Shut it!! I'll kill you if you butt in!!","TWN":"閉嘴！！你要是敢插手，我就殺了你！！"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"BASS_HARMONY_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"부전대장은 몇 번이나 날 구해줬잖아. 그러니까 이번에는 내 차례야.","JPN":"副戦隊長は何度もアタシを助けてくれたじゃないか。だから、今度はアタシの番だ。","ENG":"You saved my life so many times already. So it's my turn now.","TWN":"副戰隊長救了我好幾次。所以輪到我了。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"이제, 내가 너를 구해주겠어. 주디.","JPN":"ここからは、アタシがおまえを助けてやる。ジュディ。","ENG":"Now, I'll save you, Judy.","TWN":"現在，換我來救你。茱蒂。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"narration","speaker":null,"text":{"KOREA":"하지만 너는 누구에게 의존하지 않아도 될 만큼 강해졌고.","JPN":"でも、あなたは誰にも頼らなくていいほど強くなった。","ENG":"But now, you've become strong enough to not have to depend on anyone.","TWN":"但你已經變得足夠強大，不必依賴任何人。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"narration","speaker":null,"text":{"KOREA":"반대로 나는 비겁하게 마음의 빈 자리를 너로 채우고 있었어.","JPN":"それに対し私は卑怯にも心の隙間をあなたで満たしていたわ。","ENG":"On the contrary, I've been filling the void in my heart with you like a coward.","TWN":"相反，我懦弱地用你來填補我內心的空虛。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"narration","speaker":null,"text":{"KOREA":"결국, 아무것도 달라진 게 없었어.","JPN":"結局、何も変わっていなかった。","ENG":"In the end, nothing changed.","TWN":"結果，一切都沒有改變。"},"stage":{"bg":"WHITE","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"narration","speaker":null,"text":{"KOREA":"자의든, 타의든 너는 계속해서 다른 사람을 위해 스스로를 희생하고 있었고.","JPN":"自分の意思でも他人の意思でも、あなたはずっと他人のために自分を犠牲していて。","ENG":"You never stopped sacrificing yourself for others, whether at your own choice or not.","TWN":"不管你願不願意，你都不斷地為了別人而犧牲自己。"},"stage":{"bg":"WHITE","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"narration","speaker":null,"text":{"KOREA":"자의든, 타의든 나는 계속해서 그런 너에게 의존하게 되었으니까.","JPN":"自分の意思でも他人の意思でも、私はずっとそんなあなたに依存していたから。","ENG":"But I continued to depend on you, whether at my own choice or not.","TWN":"不管你願不願意，我都一直依賴著你。"},"stage":{"bg":"WHITE","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"narration","speaker":null,"text":{"KOREA":"그러니까…….","JPN":"だから……","ENG":"So...","TWN":"這樣的話……"},"stage":{"bg":"WHITE","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"……죽여버리겠어. 카르멘.","JPN":"……殺してやる。カルメン。","ENG":"...I'm going to kill Carmen.","TWN":"……我會殺了卡門。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L33_1","type":"narration","speaker":null,"text":{"KOREA":"오직 그것만이 너를 위해 짊어질 수 있는 나의 책임.","JPN":"それが、私があなたのために背負うことができる唯一の責任。","ENG":"That is the sole responsibility that I can bear for you.","TWN":"只有這樣，才是我唯一能為你肩負起的責任。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"이 자리에서 끊어 버리겠어!!","JPN":"この場で断ち切ってやる！！","ENG":"I'll kill you here and now!!","TWN":"我會在這裡殺死卡門！！"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"narration","speaker":null,"text":{"KOREA":"오직 그것만이 너를 살리기 위한 나의 선택.","JPN":"それがあなたを救うための私の選択。","ENG":"That is the only choice I can make to save your life.","TWN":"只有這樣，才是唯一能拯救你的選擇。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"여기서 카르멘을 죽이고, 그 악기를 제거하겠어……!","JPN":"ここでカルメンを殺して、その楽器を除去する……！","ENG":"I'm going to kill Carmen and destroy the instrument...!","TWN":"我會在這裡殺死卡門，毀掉她的樂器……！"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"narration","speaker":null,"text":{"KOREA":"오직 그것만이 너의 죽음이 그림자로 얼룩지지 않길 바라는 나의 결의.","JPN":"あなたの死をシャドウに塗りつぶさせるようなことはさせない。それが私の願いであり、決意よ！","ENG":"Because it is my determination for your death to not be tainted by a Shadow.","TWN":"只有這樣，才能讓你的死亡不被一個暗影所玷污。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"내 목숨이 다하는 한이 있더라도 여기서 널 죽이겠어……!!","JPN":"たとえ私の命が尽きようと、この場であなたを殺す……！！","ENG":"Even if it costs me my life, you will die here...!!","TWN":"哪怕拼上我的性命……！也會把你殺死在這裡……！！"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"카르멘……!!","JPN":"カルメン……！！","ENG":"CARMEN...!!","TWN":"卡門……！！"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"subtitle","speaker":null,"text":{"KOREA":" 관리국 제4 수색전대 <color=#ffd34c>야크샤</color> 본부\\n회복실","JPN":" 管理局第4捜索戦隊<color=#ffd34c>ヤクシャー</color>本部\\n回復室","ENG":"Administration 4th Recon Division <color=#ffd34c>Yaksha</color> HQ\\nRecovery room","TWN":" 管理局第4偵察戰隊<color=#ffd34c>夜叉</color>總部\\n治療室"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"……뭐라고?","JPN":"……今なんて言った？","ENG":"...What?","TWN":"你說什麼？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"그럼 부전대장이 필하모닉 홀로 간 이유가……?","JPN":"じゃあ、副戦隊長がフィルハーモニーホールに向かった理由って……？","ENG":"Then the reason Deputy Commander went to Philharmonic Hall is...","TWN":"那麼，副戰隊長為什麼要去管弦樂廳……？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"그, 그렇습니다요…….","JPN":"そ、そうでやんす……","ENG":"Y-yes...","TWN":"那、那個啊……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"부전대장님은 지금껏 줄곧 그 카르멘이라는 녀석을 쫓고 있었습니다요.","JPN":"副戦隊長は今までずっとあのカルメンってやつを追ってきたのでやんす。","ENG":"She has been chasing this Carmen all along.","TWN":"副戰隊長一直在追捕那個叫卡門的傢伙。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"전대장님이…… 그림자가 되지 않게 만들기 위해서…….","JPN":"戦隊長が……シャドウになるのを阻止するため……","ENG":"So that you... wouldn't become a Shadow, Commander...","TWN":"為了不讓戰隊長……成為暗影……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"그 원인을 제거하기 위해서 말입니다요.","JPN":"その原因を除去するためでやんすよ。","ENG":"She wanted to eliminate the cause.","TWN":"她說要從根源消除……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"빌어먹을!! 왜 아무 말도 안 한 거야!! 왜 숨긴 거냐고!!","JPN":"くそ！！　なんで何も言ってくれなかったんだ！！　どうして隠した！！","ENG":"Dammit!! Why didn't anyone say anything to me?! Why did you all hide it from me?!","TWN":"該死的！！為什麼不跟我說！！為什麼要瞞著我！！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"자기 그림자는 자기가 끊어내야 한다면서!!","JPN":"自分のシャドウは自分で断ち切るべきだって言ったじゃないか！！","ENG":"You all told me that I had to defeat my own Shadow!!","TWN":"不是說必須要自己斬斷自己的暗影嗎！！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"그야…… 부전대장님은 전대장님이 엘리시움 필하모닉과 엮이지 않길 바랐으니까요.","JPN":"そりゃあ……副戦隊長は戦隊長がエリシウムフィルハーモニーと関わらないことを望んでいましたから。","ENG":"That's because... Deputy Commander didn't want you to get involved with Elysium Philharmonic, Commander.","TWN":"沒錯……可是副戰隊長不希望戰隊長與愛樂組織再有聯繫。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"혹시라도 전대장님이 녀석들에게 당하면……!!","JPN":"万が一、戦隊長がやつらにやられでもしたら……！！","ENG":"In case you are defeated by them…!!","TWN":"如果戰隊長被這些傢伙盯上……！！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"젠장!! 이러고 있을 시간이 없어!!","JPN":"くそ！！　こうしてる場合じゃない！！","ENG":"Dammit! I don't have time for this!!","TWN":"該死！！不能再這樣待下去了！！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L13_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"아, 안됩니다요! 그 몸으로 대체 어딜 간다는 겁니까요!","JPN":"だ、ダメでやんす！　その体でいったいどこ行くつもりでやんすか！","ENG":"N-no! Where do you think you're going when you're severely injured?!","TWN":"啊，不行啦！你拖著這副身體要去哪裡啊！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L14_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"우리 전대원들이 죽게 생겼는데 여기서 죽치고 있을 시간이 어디있어!!","JPN":"アタシの戦隊員が死ぬかもしれないのに、ここでのんびりしてる暇なんてないんだよ！！","ENG":"My division members are about to die! How can I just twiddle my thumbs and do nothing?!","TWN":"我們戰隊的成員有難，哪有時間在這裡待著！！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L15_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"당장 비켜!!","JPN":"そこをどけ！！","ENG":"Get out of my way!!","TWN":"快點讓開！！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"그렇지만 뾰족한 방법이 없지 않습니까요!","JPN":"でも、方法がないでやんすよ！","ENG":"But there's nothing we can do!","TWN":"但現在我們也做不了什麼！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"연합 전대가 갇혀있는 필하모닉 홀에 다이브하기 위해서는 차원함선이 필요합니다요!","JPN":"連合戦隊が閉じ込められているフィルハーモニーホールにダイブするには、次元艦船が必要でやんす！","ENG":"To save the coalition divisions trapped in Philharmonic Hall, we need to dive. And to dive, we need a dimensional ship!","TWN":"我們需要次元艦船才能躍入聯合戰隊被困的管弦樂廳！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"하지만 우주에 있는 궤도병기가 차원함선의 다이브를 차단하고 있습니다요.","JPN":"でも、宇宙にある軌道兵器が次元艦船のダイブを遮断してるでやんす。","ENG":"But the orbital weapon in space has blocked off all dimensional ships from diving.","TWN":"但是，太空中的軌道武器正在阻止次元艦船的躍入。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"결국, 그걸 먼저 해결하지 않으면, 필하모닉 홀에는 다다를 수 없는 겁니다요!!","JPN":"結局、それを先に解決しないとフィルハーモニーホールにはたどり着くことはできないでやんす！！","ENG":"So, if we don't resolve that matter first, there's no way for us to reach Philharmonic Hall!!","TWN":"結果就是，如果解決不了軌道武器，就進不了管弦樂廳！！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"그럼, 이대로 동료들이 죽어가는 걸 손 놓고 구경만 하자는 거야?","JPN":"じゃあ、このまま仲間たちが死にゆく姿をただ見守れと？","ENG":"Are you then saying that we should just watch our comrades die?","TWN":"那麼，我們就應該袖手旁觀，眼睜睜地看著我們的同伴這樣死去嗎？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L25_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"비켜!! 나는 그런 꼴 절대 못 봐!!","JPN":"どけ！！　アタシはそんなこと許さない！！","ENG":"Outta my way!! Not on my watch!!","TWN":"讓開！！我才不會容忍這種事情發生！！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"키히익!!","JPN":"キヒイッ！！","ENG":"Eep!!","TWN":"吱！！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"그런 말이 아니지 않습니까요!!","JPN":"そういう意味じゃないでやんす！！","ENG":"You know that's not what I meant!!","TWN":"我不是這個意思！！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_QM","text":{"KOREA":"아니, 아직 방법이라면 있네.","JPN":"いや、まだ方法ならある。","ENG":"No, there's still a way.","TWN":"不，還是有辦法的。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"당신은……?","JPN":"あなたは……？","ENG":"You are...?","TWN":"你是……？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L33_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그것도 오직 자네만 할 수 있는 방법이지.","JPN":"それも、君にだけできる方法だ。","ENG":"It's something that only you can do.","TWN":"那是只有你能做到的事。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"앨리스 브레이드우드.","JPN":"アリス・ブレイドウッド。","ENG":"Alice Braidwood.","TWN":"艾莉絲·布雷德伍德。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}}]`);export{e as default};